import React, { useState } from 'react';
import Product from './Product';

const ProductList = () => {
  // Quản lý trạng thái sản phẩm đang được chọn để xem chi tiết
  const [selectedProduct, setSelectedProduct] = useState(null);

  // Dữ liệu danh sách bánh
  const cakeList = [
    { 
      id: 1, name: 'Bánh Kem Dâu', price: '250.000đ', img: '/images/p1.jpg',
      ingredients: 'Dâu tây tươi, kem tươi, cốt bánh gato, bơ lạt.', size: '16cm - 20cm'
    },
    { 
      id: 2, name: 'Bánh Thập Cẩm', price: '275.000đ', img: '/images/p2.jpg',
      ingredients: 'Trái cây nhiệt đới, hạt ngũ cốc, kem phô mai.', size: '18cm'
    },
    { 
      id: 3, name: 'Bánh Chocolate', price: '350.000đ', img: '/images/p3.jpg',
      ingredients: 'Chocolate đen 70%, bột cacao, kem tươi, hạt dẻ.', size: '20cm'
    },
    { 
      id: 4, name: 'Bánh Cầu Vòng', price: '400.000đ', img: '/images/p4.jpg',
      ingredients: 'Mứt trái cây các loại, cốt bánh đa tầng, kem vanilla.', size: '22cm'
    },
  ];

  return (
    <section style={{ padding: '20px', position: 'relative' }}>
      <h2>Danh sách bánh mới</h2>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '20px' }}>
        {cakeList.map(cake => (
          <Product 
            key={cake.id} 
            cake={cake} 
            onOpenDetail={setSelectedProduct} 
          />
        ))}
      </div>

      {/* Logic hiển thị thông tin chi tiết (Modal) */}
      {selectedProduct && (
        <div className="product-info-overlay" style={overlayStyle} onClick={() => setSelectedProduct(null)}>
          <div className="product-info-card" style={infoCardStyle} onClick={(e) => e.stopPropagation()}>
            <button style={closeButtonStyle} onClick={() => setSelectedProduct(null)}>X</button>
            <img src={selectedProduct.img} alt={selectedProduct.name} style={{ width: '100%', borderRadius: '10px' }} />
            <h2 style={{ color: '#d35400' }}>{selectedProduct.name}</h2>
            <hr />
            <p><strong>Thành phần:</strong> {selectedProduct.ingredients}</p>
            <p><strong>Kích thước:</strong> {selectedProduct.size}</p>
            <p><strong>Giá:</strong> <span style={{ color: '#e67e22', fontWeight: 'bold' }}>{selectedProduct.price}</span></p>
          </div>
        </div>
      )}
    </section>
  );
};

// CSS inline cho phần Modal chi tiết (giữ nguyên từ bản cũ)
const overlayStyle = {
  position: 'fixed', top: 0, left: 0, width: '100%', height: '100%',
  backgroundColor: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000
};

const infoCardStyle = {
  backgroundColor: '#fff', padding: '30px', borderRadius: '15px', maxWidth: '400px', width: '90%',
  position: 'relative', boxShadow: '0 10px 30px rgba(0,0,0,0.5)', textAlign: 'left'
};

const closeButtonStyle = {
  position: 'absolute', top: '10px', right: '10px', border: 'none', background: '#ff4757',
  color: 'white', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer'
};

export default ProductList;
